```

**Aperonix Tip:** `map/filter/reduce` best practices for arrays!

## Functions 🔧

```javascript
// Declaration
function greet(name) { return 'Hello ' + name; }

// Expression
const multiply = function(a, b) { return a * b; };

// Arrow
const add = (a, b) => a + b;
const square = x => x * x;

// Default params
function hello(name = 'Guest') { return `Hi ${name}!`; }

// Rest params
function sum(...nums) { return nums.reduce((a, b) => a + b, 0); }

// Closure
function createCounter() {
  let count = 0;
  return { increment: () => ++count, get: () => count };
}
const c = createCounter();
c.increment(); c.increment();
console.log(c.get()); // 2

// IIFE
(() => console.log('Runs immediately!'))();
```

**Aperonix Tip:** Arrow functions ka `this` parent scope ka hota hai!

