## Fetch API & Async/Await 🌍

```javascript
// Promise chain
fetch('/api/data')
  .then(res => res.json())
  .then(data => console.log(data))
  .catch(err => console.error(err));

// Async/Await (cleaner)
async function getData() {
  try {
    const res = await fetch('/api/users');
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    return data;
  } catch (error) {
    console.error('Error:', error.message);
  }
}

// POST request
async function createItem(data) {
  const res = await fetch('/api/items', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data)
  });
  return res.json();
}

// Parallel requests
const [users, posts] = await Promise.all([
  fetch('/api/users').then(r => r.json()),
  fetch('/api/posts').then(r => r.json())
]);
```

**Aperonix Tip:** `try-catch` hamesha use karo async mein! `Promise.all` parallel calls ke liye!

## ES6 Classes — Object Oriented Programming in JS 🏗️

Class ek **blueprint** hai objects banane ka. Jaise ek mould se kai baar same shape ke objects ban sakte hain!

### Basic Class:
```javascript
class Person {
  // Constructor — object banate waqt call hota hai
  constructor(name, age) {
    this.name = name;
    this.age = age;
  }

  // Method
  greet() {
    return `Assalamu Alaikum! Main ${this.name} hoon, ${this.age} saal ka.`;
  }

  // Getter — property ki tarah access karo
  get info() {
    return `${this.name} (${this.age})`;
  }

  // Setter
  set setAge(val) {
    if (val < 0) throw new Error('Age negative nahi ho sakti!');
    this.age = val;
  }
}

const person1 = new Person('Mohammad Khan', 25);
console.log(person1.greet()); // Assalamu Alaikum! Main Mohammad Khan hoon...
console.log(person1.info);    // Mohammad Khan (25) — getter call
person1.setAge = 26;          // setter call
```

### Static Methods & Properties:
```javascript
class MathHelper {
  static PI = 3.14159;

  static square(x) { return x * x; }
  static cube(x) { return x * x * x; }
  static circleArea(r) { return MathHelper.PI * r * r; }
}

// Instance banaye bina seedha use karo
console.log(MathHelper.square(5));      // 25
console.log(MathHelper.cube(3));        // 27
console.log(MathHelper.circleArea(7));  // 153.93...
```

### Inheritance — extends & super:
```javascript
class Animal {
  constructor(name, sound) {
    this.name = name;
    this.sound = sound;
  }

  speak() {
    return `${this.name} kehta hai: ${this.sound}!`;
  }

  toString() {
    return `Animal: ${this.name}`;
  }
}

class Dog extends Animal {
  constructor(name, breed) {
    super(name, 'Woof'); // Parent constructor call karo
    this.breed = breed;
  }

  // Override parent method
  speak() {
    return `${super.speak()} (${this.breed} breed hai)`;
  }

  fetch(item) {
    return `${this.name} ne ${item} uthaya! 🐕`;
  }
}

class Cat extends Animal {
  constructor(name) {
    super(name, 'Meow');
    this.indoor = true;
  }
}

const dog = new Dog('Tommy', 'German Shepherd');
console.log(dog.speak()); // Tommy kehta hai: Woof! (German Shepherd breed hai)
console.log(dog.fetch('ball')); // Tommy ne ball uthaya!

const cat = new Cat('Mimi');
console.log(cat.speak()); // Mimi kehta hai: Meow!

console.log(dog instanceof Dog);    // true
console.log(dog instanceof Animal); // true
```

### Private Fields (Modern JS #):
```javascript
class BankAccount {
  #balance = 0; // Private field — bahar se access nahi
  #owner;

  constructor(owner, initialBalance) {
    this.#owner = owner;
    this.#balance = initialBalance;
  }

  deposit(amount) {
    if (amount <= 0) throw new Error('Amount positive hona chahiye!');
    this.#balance += amount;
    return `Rs.${amount} jama! Balance: Rs.${this.#balance}`;
  }

  withdraw(amount) {
    if (amount > this.#balance) throw new Error('Insufficient balance! 😢');
    this.#balance -= amount;
    return `Rs.${amount} nikala! Balance: Rs.${this.#balance}`;
  }

  get balance() { return this.#balance; } // Read-only access
  get owner() { return this.#owner; }
}

const acc = new BankAccount('Mohammad Khan', 1000);
console.log(acc.deposit(500));   // Rs.500 jama! Balance: Rs.1500
console.log(acc.withdraw(200));  // Rs.200 nikala! Balance: Rs.1300
console.log(acc.balance);        // 1300
// console.log(acc.#balance);    // ERROR! Private hai
```

### Real World — User Management System:
```javascript
class User {
  static #userCount = 0;

  constructor(name, email, role = 'user') {
    User.#userCount++;
    this.id = User.#userCount;
    this.name = name;
    this.email = email;
    this.role = role;
    this.createdAt = new Date();
  }

  static getUserCount() { return User.#userCount; }

  toJSON() {
    return { id: this.id, name: this.name, email: this.email, role: this.role };
  }
}

class Admin extends User {
  constructor(name, email) {
    super(name, email, 'admin');
    this.permissions = ['read', 'write', 'delete'];
  }

  hasPermission(action) {
    return this.permissions.includes(action);
  }
}

const user1 = new User('Ali', 'ali@email.com');
const user2 = new User('Sara', 'sara@email.com');
const admin = new Admin('Khan', 'khan@aperonix.com');

console.log(User.getUserCount()); // 3
console.log(admin.hasPermission('delete')); // true
console.log(JSON.stringify(admin.toJSON()));
```

💡 **Aperonix Tip:** Classes sirf syntax sugar hain — andar se JavaScript prototype-based hi hai. Private fields `#` use karo sensitive data ke liye!

## Error Handling — Bugs Se Ladna Seekho 🐛

Real applications mein errors aana normal hai. Important ye hai ki unhe gracefully handle karo taaki app crash na ho!

### Types of Errors:
```javascript
// 1. SyntaxError — code likhne mein galti
// let x = ; // SyntaxError

// 2. ReferenceError — variable exist nahi karta
try {
  console.log(undeclaredVar);
} catch (e) {
  console.log(e instanceof ReferenceError); // true
  console.log(e.message); // undeclaredVar is not defined
}

// 3. TypeError — galat type pe operation
try {
  null.property;
} catch (e) {
  console.log(e instanceof TypeError); // true
}

// 4. RangeError — valid range se bahar
try {
  new Array(-1); // RangeError
} catch (e) {
  console.log(e.message);
}
```

### try...catch...finally:
```javascript
function divide(a, b) {
  try {
    if (typeof a !== 'number' || typeof b !== 'number') {
      throw new TypeError('Dono numbers hone chahiye!');
    }
    if (b === 0) {
      throw new RangeError('Zero se divide nahi kar sakte!');
    }
    return a / b;
  } catch (error) {
    if (error instanceof TypeError) {
      console.error('Type Error:', error.message);
    } else if (error instanceof RangeError) {
      console.error('Range Error:', error.message);
    } else {
      console.error('Unknown error:', error);
    }
    return null;
  } finally {
    console.log('divide() function complete hua'); // Hamesha chalega
  }
}

console.log(divide(10, 2));   // 5
console.log(divide(10, 0));   // null (error handled)
console.log(divide('a', 2));  // null (type error)
```

### Custom Error Classes:
```javascript
// Base custom error
class AppError extends Error {
  constructor(message, code, statusCode = 500) {
    super(message);
    this.name = 'AppError';
    this.code = code;
    this.statusCode = statusCode;
    this.timestamp = new Date().toISOString();
  }
}

class ValidationError extends AppError {
  constructor(message, field) {
    super(message, 'VALIDATION_ERROR', 400);
    this.name = 'ValidationError';
    this.field = field;
  }
}

class NotFoundError extends AppError {
  constructor(resource) {
    super(`${resource} nahi mila!`, 'NOT_FOUND', 404);
    this.name = 'NotFoundError';
  }
}

class AuthError extends AppError {
  constructor(message = 'Unauthorized access!') {
    super(message, 'AUTH_ERROR', 401);
    this.name = 'AuthError';
  }
}

// Usage
function validateUser(data) {
  if (!data.email) throw new ValidationError('Email required hai!', 'email');
  if (!data.email.includes('@')) throw new ValidationError('Valid email do!', 'email');
  if (!data.password || data.password.length < 6) {
    throw new ValidationError('Password 6+ chars ka hona chahiye!', 'password');
  }
  return true;
}

try {
  validateUser({ email: 'invalid', password: '123' });
} catch (error) {
  if (error instanceof ValidationError) {
    console.error(`Field '${error.field}': ${error.message}`);
    console.error('Status:', error.statusCode);
  }
}
```

### Error Handling Patterns:
```javascript
// Pattern 1: Result Object (Go-style)
function safeJsonParse(str) {
  try {
    return { data: JSON.parse(str), error: null };
  } catch (e) {
    return { data: null, error: e.message };
  }
}

const { data, error } = safeJsonParse('{"name": "Khan"}');
if (error) console.error('Parse failed:', error);
else console.log(data.name); // Khan

// Pattern 2: Async error handling
async function fetchData(url) {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new AppError(`HTTP ${res.status}`, 'FETCH_ERROR', res.status);
    return await res.json();
  } catch (error) {
    if (error instanceof AppError) throw error;
    throw new AppError('Network error!', 'NETWORK_ERROR');
  }
}

// Pattern 3: Global error handler
window.addEventListener('error', (event) => {
  console.error('Global Error:', event.message);
  // Yahan error reporting service ko bhejo (Sentry etc.)
});

window.addEventListener('unhandledrejection', (event) => {
  console.error('Unhandled Promise:', event.reason);
  event.preventDefault();
});
```

