## JavaScript Modules — Code Ko Organize Karo 📦

Modules se tum apna code alag alag files mein divide kar sakte ho — maintainable aur reusable!

### Named Exports:
```javascript
// math.js
export const PI = 3.14159;
export const E = 2.71828;

export function add(a, b) { return a + b; }
export function subtract(a, b) { return a - b; }
export function multiply(a, b) { return a * b; }

export class Calculator {
  constructor() { this.history = []; }

  calculate(a, op, b) {
    let result;
    switch(op) {
      case '+': result = a + b; break;
      case '-': result = a - b; break;
      case '*': result = a * b; break;
      case '/': result = b !== 0 ? a / b : 'Error'; break;
    }
    this.history.push(`${a} ${op} ${b} = ${result}`);
    return result;
  }
}
```

```javascript
// main.js — Named imports
import { add, multiply, PI, Calculator } from './math.js';

console.log(add(5, 3));      // 8
console.log(PI);             // 3.14159

// Rename on import
import { subtract as sub } from './math.js';
console.log(sub(10, 4));     // 6

// Import everything
import * as MathUtils from './math.js';
console.log(MathUtils.multiply(4, 5)); // 20

const calc = new Calculator();
console.log(calc.calculate(10, '+', 5)); // 15
```

