## Browser Storage — Data Browser Mein Save Karo 💾

User ka data browser mein store karna ho (jaise cart items, theme preference, login token) to ye three options hain:

### localStorage — Permanent Storage:
```javascript
// Set
localStorage.setItem('username', 'MohammadKhan');
localStorage.setItem('theme', 'dark');

// Get
const username = localStorage.getItem('username'); // 'MohammadKhan'
const missing = localStorage.getItem('xyz');        // null

// Remove
localStorage.removeItem('theme');

// Clear all
localStorage.clear();

// Length & iteration
console.log(localStorage.length);
for (let i = 0; i < localStorage.length; i++) {
  const key = localStorage.key(i);
  console.log(key, ':', localStorage.getItem(key));
}
```

### Objects & Arrays Store Karna (JSON):
```javascript
// Object store karna
const user = { name: 'Khan', age: 25, role: 'admin' };
localStorage.setItem('user', JSON.stringify(user));

// Object wapis lena
const storedUser = JSON.parse(localStorage.getItem('user'));
console.log(storedUser.name); // 'Khan'

// Safe parsing
function getFromStorage(key, defaultValue = null) {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item) : defaultValue;
  } catch {
    return defaultValue;
  }
}

function setToStorage(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
    return true;
  } catch (e) {
    console.error('Storage full!', e);
    return false;
  }
}

// Usage
const cart = getFromStorage('cart', []);
cart.push({ id: 1, name: 'Shirt', price: 500 });
setToStorage('cart', cart);
```

### sessionStorage — Tab Band Hone Pe Delete:
```javascript
// sessionStorage bilkul localStorage jaisa hai
// Fark: tab/browser band karne pe sab delete

sessionStorage.setItem('tempData', 'will disappear');
sessionStorage.setItem('formStep', '2'); // Multi-step form ke liye

// Same methods: getItem, removeItem, clear
const step = sessionStorage.getItem('formStep'); // '2'
```

### Cookies — More Control, More Complex:
```javascript
// Basic cookie set karna
document.cookie = 'username=MohammadKhan';
document.cookie = 'theme=dark; expires=Fri, 31 Dec 2025 23:59:59 GMT';
document.cookie = 'sessionId=abc123; path=/; secure; samesite=strict';

// Cookie helper functions
const Cookies = {
  set(name, value, days = 7, options = {}) {
    const date = new Date();
    date.setTime(date.getTime() + days * 24 * 60 * 60 * 1000);
    const expires = `expires=${date.toUTCString()}`;
    const secure = options.secure ? '; secure' : '';
    const sameSite = `; samesite=${options.sameSite || 'strict'}`;
    document.cookie = `${name}=${encodeURIComponent(value)}; ${expires}; path=/` + secure + sameSite;
  },

  get(name) {
    const nameEQ = name + '=';
    const cookies = document.cookie.split(';');
    for (let c of cookies) {
      c = c.trim();
      if (c.startsWith(nameEQ)) {
        return decodeURIComponent(c.substring(nameEQ.length));
      }
    }
    return null;
  },

  delete(name) {
    this.set(name, '', -1);
  }
};

Cookies.set('userToken', 'eyJhbGci...', 30);
console.log(Cookies.get('userToken'));
Cookies.delete('userToken');
```

### Comparison Table:
```
| Feature         | localStorage  | sessionStorage | Cookies       |
|-----------------|---------------|----------------|---------------|
| Capacity        | ~5-10MB       | ~5-10MB        | ~4KB          |
| Expires         | Never         | Tab close      | Custom        |
| Server access   | ❌ No         | ❌ No          | ✅ Yes        |
| Sent in HTTP    | ❌ No         | ❌ No          | ✅ Auto       |
| JS Access       | ✅ Yes        | ✅ Yes         | ✅ (if !httpOnly)|
```

### Practical — Settings Manager:
```javascript
class SettingsManager {
  static STORAGE_KEY = 'aperonix-settings';

  static defaults = {
    theme: 'light',
    language: 'en',
    fontSize: 14,
    notifications: true
  };

  static get() {
    const saved = localStorage.getItem(this.STORAGE_KEY);
    return saved ? { ...this.defaults, ...JSON.parse(saved) } : { ...this.defaults };
  }

  static set(key, value) {
    const settings = this.get();
    settings[key] = value;
    localStorage.setItem(this.STORAGE_KEY, JSON.stringify(settings));
    return settings;
  }

  static reset() {
    localStorage.removeItem(this.STORAGE_KEY);
    return { ...this.defaults };
  }
}

const settings = SettingsManager.get();
console.log(settings.theme); // 'light'

