```

### Infinite Sequences:
```javascript
// Infinite ID generator
function* idGenerator(start = 1) {
  while (true) {
    yield start++;
  }
}

const getId = idGenerator();
console.log(getId.next().value); // 1
console.log(getId.next().value); // 2
console.log(getId.next().value); // 3
// ... kabhi khatam nahi hoga (jab tak next() call karo)

// Fibonacci sequence
function* fibonacci() {
  let [a, b] = [0, 1];
