### Generator with Input (next() mein value bhejo):
```javascript
function* calculator() {
  let result = 0;
  while (true) {
    const input = yield result; // yield ka value = jo next() mein diya
    if (input === null) break;
    result += input;
  }
  return result;
}

const calc = calculator();
console.log(calc.next().value);   // 0 (start)
console.log(calc.next(10).value); // 10 (added 10)
console.log(calc.next(20).value); // 30 (added 20)
console.log(calc.next(5).value);  // 35 (added 5)
console.log(calc.next(null));     // {value: 35, done: true}
