}
```

### Custom Iterator:
```javascript
class Range {
  constructor(start, end, step = 1) {
    this.start = start;
    this.end = end;
    this.step = step;
  }

  [Symbol.iterator]() {
    let current = this.start;
    const { end, step } = this;
    return {
      next() {
        if (current <= end) {
          const value = current;
          current += step;
          return { value, done: false };
        }
        return { value: undefined, done: true };
      }
    };
  }
}

const range = new Range(1, 10, 2); // 1 to 10, step 2
console.log([...range]); // [1, 3, 5, 7, 9]

for (const n of new Range(0, 100, 10)) {
  console.log(n); // 0, 10, 20, ..., 100
}
```

