## Event Loop — JS Ka Dil ❤️

JavaScript single-threaded hai — ek waqt mein ek kaam. Lekin phir bhi async kaam kaise hota hai? Event Loop ki wajah se!

### JavaScript Runtime Components:
```
┌─────────────────────────────┐
│    JavaScript Engine         │
│  ┌──────────────────────┐   │
│  │    Call Stack        │   │
│  │  ┌────────────────┐  │   │
│  │  │ console.log()  │  │   │
│  │  ├────────────────┤  │   │
│  │  │   doSomething()│  │   │
│  │  └────────────────┘  │   │
│  └──────────────────────┘   │
└─────────────────────────────┘
        ↕ Event Loop
┌──────────────────────────────┐
│  Microtask Queue (Priority)  │
│  [Promise.then, queueMicrotask]│
├──────────────────────────────┤
│  Macrotask Queue             │
│  [setTimeout, setInterval,   │
│   setImmediate, I/O]         │
└──────────────────────────────┘
```

### Execution Order:
```javascript
console.log('1 — Synchronous');

setTimeout(() => console.log('2 — Macrotask (setTimeout 0)'), 0);

Promise.resolve().then(() => console.log('3 — Microtask (Promise)'));

queueMicrotask(() => console.log('4 — Microtask (queueMicrotask)'));

setTimeout(() => console.log('5 — Macrotask (setTimeout 100)'), 100);

console.log('6 — Synchronous');

// Output ORDER:
// 1 — Synchronous
// 6 — Synchronous      (call stack clear hota hai)
// 3 — Microtask (Promise)     (microtasks PEHLE)
// 4 — Microtask (queueMicrotask)
// 2 — Macrotask (setTimeout 0)  (macrotasks baad mein)
// 5 — Macrotask (setTimeout 100)
```

### Microtasks vs Macrotasks:
```javascript
// MICROTASKS (high priority) — call stack ke baad TURANT:
// - Promise.then(), Promise.catch(), Promise.finally()
// - async/await (internally Promise use karta hai)
// - queueMicrotask()
// - MutationObserver

// MACROTASKS (lower priority) — next event loop iteration:
// - setTimeout, setInterval, setImmediate
// - I/O operations (file read/write)
// - requestAnimationFrame
// - UI rendering events

// Example — Microtask priority:
const promise = Promise.resolve('promise value');

setTimeout(() => {
  console.log('Timeout 1');
  promise.then(v => console.log('Promise inside Timeout:', v));
}, 0);

promise.then(v => console.log('Promise 1:', v));

setTimeout(() => console.log('Timeout 2'), 0);

promise.then(v => console.log('Promise 2:', v));

// Output:
// Promise 1: promise value
// Promise 2: promise value
// Timeout 1
// Promise inside Timeout: promise value  ← microtask runs before Timeout 2!
// Timeout 2
```

### Blocking vs Non-blocking:
```javascript
// BLOCKING — call stack rok deta hai
function blockingOperation() {
  const start = Date.now();
  while (Date.now() - start < 3000) {} // 3 second block!
  console.log('Blocking done');
}

// Page 3 second ke liye unresponsive ho jata hai!
btn.addEventListener('click', blockingOperation);

// NON-BLOCKING — async karo
async function nonBlockingOperation() {
  // Heavy kaam chunks mein karo
  const chunks = createChunks(largeArray, 1000);

  for (const chunk of chunks) {
    processChunk(chunk);
    await new Promise(resolve => setTimeout(resolve, 0)); // Yield control
  }
  console.log('Done without blocking!');
}
```

### requestAnimationFrame — Smooth Animations:
```javascript
function animate() {
  // Screen refresh se pehle chalega (~60fps)
  requestAnimationFrame((timestamp) => {
    // Timestamp = ms since page load
    const progress = (timestamp % 2000) / 2000; // 2 second cycle

    element.style.transform = `translateX(${progress * 300}px)`;

    animate(); // Next frame
  });
}

animate();

// setInterval se behtar kyunki:
// 1. Browser refresh rate ke saath sync
// 2. Tab inactive hone pe pause
// 3. Smoother animations
```

### setTimeout & setInterval Gotchas:
```javascript
// setTimeout(fn, 0) matlab turant nahi — microtasks ke BAAD
setTimeout(() => console.log('Not immediate!'), 0);
Promise.resolve().then(() => console.log('This runs FIRST'));

// setInterval drift problem
let count = 0;
const interval = setInterval(() => {
  count++;
  if (count >= 5) clearInterval(interval);
  console.log('Count:', count);
}, 1000);

// Better: setTimeout recursive (no drift)
function accurateRepeat(fn, delay) {
  let start = Date.now();

  function loop() {
    const elapsed = Date.now() - start;
    fn();
    start = Date.now();
    setTimeout(loop, Math.max(0, delay - (Date.now() - start)));
  }

  setTimeout(loop, delay);
}
```

💡 **Aperonix Tip:** Event Loop samajhna JavaScript ka MOST IMPORTANT concept hai interviews ke liye. Yaad rakho: Synchronous → Microtasks → Macrotasks. Har baar!

## Design Patterns — Professional Code Likhna 🏆

Design patterns tried-and-tested solutions hain common problems ke liye. Senior developers ye patterns use karte hain!

### 1. Singleton Pattern — Ek Hi Instance:
```javascript
class ConfigManager {
  static #instance = null;

  #config = {
    apiUrl: 'https://api.aperonix.com',
    timeout: 5000,
    debug: false
  };

  constructor() {
    if (ConfigManager.#instance) {
      return ConfigManager.#instance;
    }
    ConfigManager.#instance = this;
  }

  get(key) { return this.#config[key]; }
  set(key, value) { this.#config[key] = value; }
  getAll() { return { ...this.#config }; }
}

const config1 = new ConfigManager();
const config2 = new ConfigManager();
console.log(config1 === config2); // true — same instance!

config1.set('debug', true);
console.log(config2.get('debug')); // true — same object!
```

### 2. Observer Pattern — Events Ka System:
```javascript
class EventEmitter {
  #events = {};

  on(event, listener) {
    if (!this.#events[event]) this.#events[event] = [];
    this.#events[event].push(listener);
    return () => this.off(event, listener); // Unsubscribe function
  }

  off(event, listener) {
    this.#events[event] = (this.#events[event] || []).filter(l => l !== listener);
  }

  emit(event, ...args) {
    (this.#events[event] || []).forEach(listener => listener(...args));
  }

  once(event, listener) {
    const wrapper = (...args) => {
      listener(...args);
      this.off(event, wrapper);
    };
    this.on(event, wrapper);
  }
}

const bus = new EventEmitter();

// Subscribe
const unsubscribe = bus.on('user:login', (user) => {
  console.log(`${user.name} logged in! 🎉`);
});

bus.on('user:login', (user) => {
  console.log(`Sending welcome email to ${user.email}`);
});

// Emit
bus.emit('user:login', { name: 'Khan', email: 'khan@aperonix.com' });

// Unsubscribe
unsubscribe();
```

### 3. Factory Pattern — Objects Banane Ka Factory:
```javascript
class Button {
  constructor(type, text, color) {
    this.type = type;
    this.text = text;
    this.color = color;
  }

  render() {
    return `<button class="btn btn-${this.type}" style="background:${this.color}">${this.text}</button>`;
  }
}

class ButtonFactory {
  static create(type, text) {
    const configs = {
      primary:  { color: '#764ba2', text: text || 'Primary' },
      danger:   { color: '#e74c3c', text: text || 'Delete' },
      success:  { color: '#2ecc71', text: text || 'Success' },
      warning:  { color: '#f39c12', text: text || 'Warning' }
    };

    const config = configs[type] || configs.primary;
    return new Button(type, config.text, config.color);
  }
}

const saveBtn = ButtonFactory.create('primary', 'Save Changes');
const deleteBtn = ButtonFactory.create('danger', 'Delete User');
console.log(saveBtn.render());
console.log(deleteBtn.render());
```

### 4. Module Pattern — Private State:
```javascript
const ShoppingCart = (() => {
  // Private state
  let items = [];
  let discount = 0;

  // Private functions
  function calculateTotal() {
    const subtotal = items.reduce((sum, item) => sum + item.price * item.qty, 0);
    return subtotal * (1 - discount / 100);
  }

  // Public API
  return {
    addItem(item) {
      const existing = items.find(i => i.id === item.id);
      if (existing) existing.qty++;
      else items.push({ ...item, qty: 1 });
      return this;
    },

    removeItem(id) {
      items = items.filter(i => i.id !== id);
      return this;
    },

    setDiscount(percent) {
      discount = percent;
      return this;
    },

    getTotal() { return calculateTotal(); },
    getItems() { return [...items]; },
    clear() { items = []; return this; }
  };
})();

// Method chaining!
ShoppingCart
  .addItem({ id: 1, name: 'Shirt', price: 500 })
  .addItem({ id: 2, name: 'Pants', price: 1200 })
  .setDiscount(10);

console.log(ShoppingCart.getTotal()); // 1530 (10% off)
```

### 5. Strategy Pattern — Interchangeable Algorithms:
```javascript
// Sorting strategy
const sortStrategies = {
  byName: (a, b) => a.name.localeCompare(b.name),
  byPrice: (a, b) => a.price - b.price,
  byPriceDesc: (a, b) => b.price - a.price,
  byDate: (a, b) => new Date(a.createdAt) - new Date(b.createdAt)
};

class ProductList {
  constructor(products) {
    this.products = products;
  }

  sort(strategy = 'byName') {
    if (!sortStrategies[strategy]) {
      throw new Error(`Unknown strategy: ${strategy}`);
    }
    return [...this.products].sort(sortStrategies[strategy]);
  }

  // Add custom strategy
  addStrategy(name, compareFn) {
    sortStrategies[name] = compareFn;
  }
}

const products = new ProductList([
  { name: 'Pants', price: 1200 },
  { name: 'Shirt', price: 500 },
  { name: 'Shoes', price: 2500 }
]);

console.log(products.sort('byPrice'));
// [{name:'Shirt', price:500}, ...]
