  // ===== APERONIX QUIZ APP =====
  // Advanced JavaScript — Created by Mohammad Khan

  class QuizApp {
    constructor() {
      this.questions = [];
      this.currentIndex = 0;
      this.score = 0;
      this.timer = null;
      this.timeLeft = 15;
      this.answered = false;

      this.elements = {
        loading: document.getElementById('loadingScreen'),
        quiz: document.getElementById('quizScreen'),
        result: document.getElementById('resultScreen'),
        question: document.getElementById('questionText'),
        options: document.getElementById('optionsGrid'),
        counter: document.getElementById('questionCounter'),
        progress: document.getElementById('progressFill'),
        score: document.getElementById('scoreDisplay'),
        nextBtn: document.getElementById('nextBtn'),
        timerFill: document.getElementById('timerFill'),
        finalScore: document.getElementById('finalScore'),
        resultMsg: document.getElementById('resultMessage'),
        resultEmoji: document.getElementById('resultEmoji'),
        highScore: document.getElementById('highScoreDisplay'),
        restartBtn: document.getElementById('restartBtn')
      };

      this.elements.nextBtn.addEventListener('click', () => this.nextQuestion());
      this.elements.restartBtn.addEventListener('click', () => this.restart());
    }

    async init() {
      try {
        // Free quiz API
        const response = await fetch('https://opentdb.com/api.php?amount=10&type=multiple&difficulty=medium');
        if (!response.ok) throw new Error('API error');
        const data = await response.json();

        // Questions prepare karo
        this.questions = data.results.map((q, i) => ({
          id: i,
          text: this.decodeHTML(q.question),
          correct: this.decodeHTML(q.correct_answer),
          options: this.shuffle([
            q.correct_answer,
            ...q.incorrect_answers
          ].map(o => this.decodeHTML(o)))
        }));

        this.showScreen('quiz');
        this.renderQuestion();
      } catch (error) {
        // Fallback questions
        this.questions = this.getFallbackQuestions();
        this.showScreen('quiz');
        this.renderQuestion();
      }
    }

    decodeHTML(html) {
      const txt = document.createElement('textarea');
      txt.innerHTML = html;
      return txt.value;
    }

    shuffle(arr) {
      return [...arr].sort(() => Math.random() - 0.5);
    }

    showScreen(screen) {
      ['loading', 'quiz', 'result'].forEach(s => {
        this.elements[s].style.display = s === screen ? 'block' : 'none';
      });
    }

    renderQuestion() {
      const q = this.questions[this.currentIndex];
      this.answered = false;

      // Update UI
      this.elements.question.textContent = q.text;
      this.elements.counter.textContent = `Question ${this.currentIndex + 1}/${this.questions.length}`;
      this.elements.progress.style.width = `${(this.currentIndex / this.questions.length) * 100}%`;
      this.elements.score.textContent = this.score;
      this.elements.nextBtn.style.display = 'none';

      // Options render karo
      this.elements.options.innerHTML = q.options.map((opt, i) => `
        <button class="option-btn" data-index="${i}" onclick="quiz.selectAnswer(this, '${opt.replace(/'/g, "\\'")}')">  
          <span style="margin-right:10px;opacity:0.5">${['A','B','C','D'][i]}.</span>${opt}
        </button>
      `).join('');

      this.startTimer();
    }

    startTimer() {
      this.timeLeft = 15;
      clearInterval(this.timer);

      this.timer = setInterval(() => {
        this.timeLeft -= 0.1;
        this.elements.timerFill.style.width = `${(this.timeLeft / 15) * 100}%`;

        if (this.timeLeft <= 5) this.elements.timerFill.style.background = '#f87171';
        else this.elements.timerFill.style.background = 'linear-gradient(90deg, #34d399, #60a5fa)';

        if (this.timeLeft <= 0) {
          clearInterval(this.timer);
          if (!this.answered) this.timeUp();
        }
      }, 100);
    }

    timeUp() {
      this.answered = true;
      const q = this.questions[this.currentIndex];

      // Sahi answer highlight karo
      document.querySelectorAll('.option-btn').forEach(btn => {
        btn.disabled = true;
        if (btn.textContent.includes(q.correct)) btn.classList.add('correct');
      });

      this.elements.nextBtn.style.display = 'block';
    }

    selectAnswer(btn, selected) {
      if (this.answered) return;
      this.answered = true;
      clearInterval(this.timer);

      const q = this.questions[this.currentIndex];
      const isCorrect = selected === q.correct;

      // Disable all buttons
      document.querySelectorAll('.option-btn').forEach(b => {
        b.disabled = true;
        if (b.textContent.includes(q.correct)) b.classList.add('correct');
      });

      if (isCorrect) {
        btn.classList.add('correct');
        this.score++;
      } else {
        btn.classList.add('wrong');
      }

      this.elements.score.textContent = this.score;
      this.elements.nextBtn.style.display = 'block';
    }

    nextQuestion() {
      this.currentIndex++;
      if (this.currentIndex < this.questions.length) {
        this.renderQuestion();
      } else {
        this.showResults();
      }
    }

    showResults() {
      clearInterval(this.timer);
      const total = this.questions.length;
      const percentage = (this.score / total) * 100;

      let emoji, message;
      if (percentage >= 90) { emoji = '🏆'; message = 'Zabardast! Tum JavaScript expert ho!'; }
      else if (percentage >= 70) { emoji = '🌟'; message = 'Bahut acha! Keep it up!'; }
      else if (percentage >= 50) { emoji = '👍'; message = 'Theek hai! Aur practice karo!'; }
      else { emoji = '📚'; message = 'Koi baat nahi! Aperonix se seekhte raho!'; }

      // High score check
      const hiScore = localStorage.getItem('quiz-highscore') || 0;
      if (this.score > hiScore) {
        localStorage.setItem('quiz-highscore', this.score);
        this.elements.highScore.innerHTML = `<span style="color:#fbbf24">🎉 Naya High Score!</span>`;
      } else {
        this.elements.highScore.innerHTML = `Best: ${hiScore}/${total}`;
      }

      this.elements.resultEmoji.textContent = emoji;
      this.elements.finalScore.textContent = `${this.score}/${total}`;
      this.elements.resultMsg.textContent = message;

      this.showScreen('result');
    }

    restart() {
      this.currentIndex = 0;
      this.score = 0;
      this.answered = false;
      clearInterval(this.timer);
      this.showScreen('loading');
      this.init();
    }

    getFallbackQuestions() {
      return [
        { id: 0, text: 'JavaScript mein `typeof null` kya return karta hai?', correct: 'object', options: ['null', 'object', 'undefined', 'string'] },
        { id: 1, text: '`===` aur `==` mein kya fark hai?', correct: 'Strict equality (value + type)', options: ['Strict equality (value + type)', 'Same hain', 'Only value check', 'Only type check'] },
        { id: 2, text: 'JavaScript mein `let` aur `var` mein scope ka kya fark hai?', correct: 'let block-scoped hai, var function-scoped', options: ['let block-scoped hai, var function-scoped', 'Dono same hain', 'var block-scoped hai', 'let global hai'] },
        { id: 3, text: 'Falsy values kaunsi hain?', correct: '0, "", null, undefined, NaN, false', options: ['0, "", null, undefined, NaN, false', 'Sirf false', '0 aur null', 'Sirf null aur undefined'] },
        { id: 4, text: 'Array ka `map()` kya karta hai?', correct: 'Naya transformed array return karta hai', options: ['Naya transformed array return karta hai', 'Original array modify karta hai', 'Array filter karta hai', 'Array sort karta hai'] }
      ];
    }
  }

  const quiz = new QuizApp();
  quiz.init();
  </script>
